# JobFlow Autofill - System Architecture

## 1. Overview

JobFlow Autofill is a local-first job application assistant that combines:
- **Form Autofill**: Browser extension that detects and auto-fills job application forms
- **Application Tracking**: Dashboard to manage job applications through pipeline stages
- **Follow-up Reminders**: Notifications for timely follow-ups

## 2. Architecture Diagram

```
┌─────────────────────────────────────────────────────────────────┐
│                        JobFlow Autofill                          │
├─────────────────────────────────────────────────────────────────┤
│                                                                  │
│  ┌──────────────────────┐     ┌──────────────────────────────┐  │
│  │   Browser Extension  │     │        Web Dashboard         │  │
│  │                      │     │                              │  │
│  │  - Form Detection    │     │  - Application Management    │  │
│  │  - Auto-fill         │◄───►│  - Profile Editor            │  │
│  │  - Field Mapping     │     │  - Pipeline View             │  │
│  │                      │     │  - Analytics                 │  │
│  └──────────────────────┘     └──────────────────────────────┘  │
│              │                           │                      │
│              ▼                           ▼                      │
│  ┌──────────────────────────────────────────────────────────┐  │
│  │                    Local Storage Layer                    │  │
│  │                                                           │  │
│  │  ┌─────────────┐  ┌─────────────┐  ┌─────────────────┐   │  │
│  │  │  IndexedDB  │  │ LocalStorage│  │  Extension DB   │   │  │
│  │  │ (Profile,   │  │ (Settings,  │  │  (Form Schemas, │   │  │
│  │  │  Applications)│ │  UI State) │  │   Mappings)     │   │  │
│  │  └─────────────┘  └─────────────┘  └─────────────────┘   │  │
│  └──────────────────────────────────────────────────────────┘  │
│                                                                  │
│  ┌──────────────────────────────────────────────────────────┐  │
│  │              Native Notifications Service                  │  │
│  │  - Follow-up reminders                                    │  │
│  │  - Application status updates                             │  │
│  └──────────────────────────────────────────────────────────┘  │
│                                                                  │
└─────────────────────────────────────────────────────────────────┘
```

## 3. Tech Stack

| Component | Technology | Rationale |
|-----------|------------|-----------|
| Web Framework | React 18 + TypeScript | Type safety, component ecosystem |
| Build Tool | Vite | Fast dev, optimized builds |
| State Management | Zustand | Lightweight, TypeScript-friendly |
| Storage (Local) | Dexie.js (IndexedDB) | Promise-based IndexedDB wrapper |
| Storage (Cloud) | Supabase (PostgreSQL) | Auth, RLS, real-time subscriptions |
| UI Components | Tailwind CSS + Radix UI | Customizable, accessible |
| Browser Extension | Chrome Extension API | Form detection, autofill |
| Notifications | Browser Notifications API | Cross-browser support |
| Date Handling | date-fns | Lightweight date utilities |

## 4. Data Models

### 4.1 User Profile

```typescript
interface UserProfile {
  id: string;
  personal: {
    firstName: string;
    lastName: string;
    email: string;
    phone: string;
    location: {
      address: string;
      city: string;
      state: string;
      zip: string;
      country: string;
    };
    linkedIn?: string;
    portfolio?: string;
    website?: string;
  };
  workExperience: WorkExperience[];
  education: Education[];
  skills: string[];
  documents: Document[];
  answers: SavedAnswer[];
  createdAt: Date;
  updatedAt: Date;
}

interface WorkExperience {
  id: string;
  company: string;
  title: string;
  location: string;
  startDate: string;
  endDate: string | null; // null = current
  description: string;
}

interface Education {
  id: string;
  institution: string;
  degree: string;
  field: string;
  graduationDate: string;
  gpa?: string;
}

interface Document {
  id: string;
  name: string;
  type: 'resume' | 'cover-letter' | 'other';
  content: string; // Base64 or file path
  mimeType: string;
}

interface SavedAnswer {
  id: string;
  question: string;
  answer: string;
  tags: string[];
}
```

### 4.2 Application

```typescript
interface JobApplication {
  id: string;
  company: string;
  position: string;
  source: string;
  sourceUrl?: string;
  appliedDate: string;
  status: ApplicationStatus;
  stage: PipelineStage;
  nextAction?: NextAction;
  notes: string;
  contacts: Contact[];
  followUpDate?: string;
  salary?: {
    amount: number;
    currency: string;
    frequency: 'hourly' | 'yearly';
  };
  createdAt: Date;
  updatedAt: Date;
}

type ApplicationStatus = 'active' | 'archived' | 'deleted';
type PipelineStage = 'applied' | 'interviewing' | 'offer' | 'rejected' | 'closed';

interface NextAction {
  type: 'follow-up' | 'interview' | 'decision' | 'other';
  dueDate: string;
  description: string;
}

interface Contact {
  id: string;
  name: string;
  role: string;
  email?: string;
  phone?: string;
  notes: string;
}
```

### 4.3 Form Schema

```typescript
interface FormSchema {
  id: string;
  domain: string;
  urlPattern: string;
  fieldMappings: FieldMapping[];
  createdAt: Date;
}

interface FieldMapping {
  formField: string; // CSS selector or name
  profileField: string; // Path in UserProfile (e.g., "personal.firstName")
  transform?: 'none' | 'uppercase' | 'lowercase' | 'capitalize';
}
```

## 5. Module Design

### 5.1 Core Modules

```
src/
├── core/                    # Shared business logic
│   ├── profile/             # Profile management
│   │   ├── profile.service.ts
│   │   ├── profile.store.ts
│   │   └── profile.types.ts
│   ├── applications/        # Application tracking
│   │   ├── application.service.ts
│   │   ├── application.store.ts
│   │   └── application.types.ts
│   ├── auth/                # User authentication (NEW)
│   │   ├── auth.store.ts
│   │   └── auth.hooks.ts
│   ├── notifications/       # Notifications (NEW)
│   │   ├── notifications.store.ts
│   │   └── browser-notifications.ts
│   ├── storage/             # IndexedDB + Supabase abstraction
│   │   ├── db.ts            # IndexedDB (Dexie)
│   │   ├── supabase.ts      # Cloud sync client
│   │   └── repositories/
│   └── sync/                # Cross-context sync (extension ↔ web)
│
├── features/
│   ├── dashboard/          # Main dashboard view
│   ├── profile-editor/     # Profile management UI
│   ├── applications/       # Application list/kanban
│   ├── pipeline/           # Pipeline view
│   └── settings/           # App settings
│
├── components/              # Reusable UI components
├── hooks/                   # Custom React hooks
├── utils/                   # Utility functions
└── lib/                     # Third-party integrations
```

### 5.2 Browser Extension Structure

```
extension/
├── manifest.json
├── background/
│   └── background.ts       # Service worker
├── content/
│   ├── content.ts          # Page injection
│   ├── form-detector.ts    # Form field detection
│   └── autofill.ts         # Auto-fill logic
├── popup/
│   ├── popup.tsx           # Extension popup
│   └── QuickProfile/
└── shared/                 # Shared types/utils
```

## 6. Database Schema

### 6.1 Cloud Database (Supabase)

The cloud database supports optional user authentication and cross-device sync.

#### Tables

| Table | Purpose |
|-------|---------|
| `profiles` | Extended user profile data, sync metadata |
| `user_settings` | User preferences (notifications, autofill, theme) |
| `notifications` | In-app notifications with scheduling |
| `synced_applications` | Cloud backup of job applications |
| `synced_contacts` | Contacts linked to synced applications |

#### Key Relationships

```
auth.users (Supabase)
    └── profiles (1:1)
        ├── user_settings (1:1)
        ├── notifications (1:N)
        └── synced_applications (1:N)
                └── synced_contacts (1:N)
```

#### Row Level Security

All tables use RLS policies ensuring users can only access their own data:
- SELECT: `auth.uid() = user_id`
- INSERT/UPDATE/DELETE: `auth.uid() = user_id`

### 6.2 Local Database (IndexedDB)

Primary storage for offline-first operation.

| Store | Purpose |
|-------|---------|
| `profiles` | User profile data |
| `applications` | Job applications |
| `formSchemas` | Domain-specific form mappings |
| `settings` | App settings |
| `notifications` | Local notifications queue |
| `syncQueue` | Pending sync operations |
| `syncStatus` | Sync state tracking |

### 6.3 Sync Strategy

1. **Offline-first**: All writes go to IndexedDB first
2. **Background sync**: Changes queued in `syncQueue` for cloud sync
3. **Conflict resolution**: Last-write-wins with timestamp comparison
4. **Selective sync**: Users can enable/disable cloud sync per data type

## 7. Key Design Decisions

### 7.1 Local-First with Optional Cloud

**Decision**: Primary storage is IndexedDB; Supabase is optional for auth and sync.

**Rationale**:
- Privacy: Users control what data (if any) is synced to cloud
- Offline-capable: Core functionality works without internet
- Flexibility: Users can use app anonymously or with account
- Future-proof: Cloud sync ready when users want it

### 7.2 Extension ↔ Web Sync

**Decision**: Use `window.postMessage` + Broadcast Channel API for communication between extension and web dashboard.

**Rationale**:
- No backend required
- Works on same origin
- Simple, reliable message passing

### 7.3 Form Detection Strategy

**Decision**: Combination of:
1. Common field name matching (email, phone, company, etc.)
2. Domain-specific schemas (stored mappings for known job sites)
3. Heuristic analysis (label association, placeholder patterns)

**Rationale**: Balances coverage with accuracy. Start with common patterns, let users create custom mappings.

### 7.4 Notification Strategy

**Decision**: Dual notification system:
- **Browser notifications**: Follow-up reminders, application updates via Web Notifications API
- **In-app notifications**: Stored in database, support scheduling and read/unread state

**Rationale**: 
- Browser notifications for time-sensitive alerts even when app is closed
- In-app notifications for persistent record and detailed history

## 8. Security Considerations

1. **Data at Rest**: IndexedDB is origin-isolated; extension has access only to its own storage
2. **Cloud Data**: Supabase RLS ensures users can only access their own data
3. **Sensitive Fields**: Mark fields as sensitive (SSN, salary expectations) for extra confirmation before autofill
4. **Content Security**: Sanitize all user input before rendering
5. **Auth Tokens**: Stored securely via Supabase client with automatic refresh

## 9. Future Considerations (Out of Scope)

- Encrypted cloud sync
- Mobile companion app
- AI-powered cover letter generation
- Application analytics
- Team/recruiter sharing
- Push notifications (PWA)

## 10. Acceptance Criteria

### Core Features
- [ ] User can create and edit profile with all resume fields
- [ ] User can add/edit/delete job applications
- [ ] User can view applications in pipeline/kanban view
- [ ] User receives follow-up reminders
- [ ] Browser extension detects common job application forms
- [ ] Browser extension autofills detected forms from profile
- [ ] All data persists locally between sessions

### User Authentication (NEW)
- [ ] User can sign up with email/password
- [ ] User can sign in with email/password
- [ ] User can sign in with Google/GitHub OAuth
- [ ] User can sign out
- [ ] Session persists across browser sessions
- [ ] User profile syncs to cloud when logged in

### Notifications (NEW)
- [ ] User receives browser notifications for follow-ups
- [ ] User can view notification history in app
- [ ] User can mark notifications as read
- [ ] User can dismiss notifications
- [ ] Notifications can be scheduled for future delivery
- [ ] Notification preferences can be customized

import Dexie, { Table } from 'dexie'
import type { 
  UserProfile, 
  JobApplication, 
  FormSchema, 
  AppSettings,
  Notification,
  SyncStatus
} from '../types'

// ============================================================================
// IndexedDB Schema (Local-First Storage)
// ============================================================================

export class JobFlowDatabase extends Dexie {
  // Core tables
  profiles!: Table<UserProfile>
  applications!: Table<JobApplication>
  formSchemas!: Table<FormSchema>
  settings!: Table<AppSettings & { id: string }>

  // New tables for auth & notifications
  notifications!: Table<Notification>
  syncQueue!: Table<SyncQueueItem>
  syncStatus!: Table<SyncStatus & { id: string }>

  constructor() {
    super('JobFlowDB')

    // Version 2 adds notifications and sync tables
    this.version(2).stores({
      profiles: 'id, createdAt, updatedAt',
      applications: 'id, company, status, stage, appliedDate, createdAt, followUpDate',
      formSchemas: 'id, domain, urlPattern',
      settings: 'id',
      // New tables
      notifications: 'id, userId, type, priority, scheduledFor, readAt, createdAt, [userId+readAt]',
      syncQueue: '++id, entityType, entityId, action, createdAt',
      syncStatus: 'id'
    })
  }
}

// Sync queue for offline-first sync
export interface SyncQueueItem {
  id?: number
  entityType: 'application' | 'profile' | 'settings' | 'notification'
  entityId: string
  action: 'create' | 'update' | 'delete'
  payload: Record<string, unknown>
  createdAt: Date
  retryCount: number
  lastError?: string
}

export const db = new JobFlowDatabase()

// ============================================================================
// Database Initialization
// ============================================================================

export async function initializeDatabase() {
  const settingsCount = await db.settings.count()
  if (settingsCount === 0) {
    await db.settings.add({
      id: 'default',
      notifications: {
        enabled: true,
        followUpReminderDays: 7
      },
      autofill: {
        autoSubmit: false,
        confirmBeforeFill: true
      },
      theme: 'system'
    })
  }

  const syncStatusCount = await db.syncStatus.count()
  if (syncStatusCount === 0) {
    await db.syncStatus.add({
      id: 'default',
      lastSyncAt: null,
      syncInProgress: false,
      syncEnabled: false,
      pendingChanges: 0,
      lastError: null
    })
  }
}

// ============================================================================
// Profile Repository
// ============================================================================

export const profileRepository = {
  async get(): Promise<UserProfile | undefined> {
    return db.profiles.toCollection().first()
  },

  async save(profile: UserProfile): Promise<string> {
    profile.updatedAt = new Date()
    await db.profiles.put(profile)
    return profile.id
  },

  async create(profile: Omit<UserProfile, 'id' | 'createdAt' | 'updatedAt'>): Promise<string> {
    const now = new Date()
    const newProfile: UserProfile = {
      ...profile,
      id: crypto.randomUUID(),
      createdAt: now,
      updatedAt: now
    }
    await db.profiles.add(newProfile)
    return newProfile.id
  },

  async delete(): Promise<void> {
    await db.profiles.clear()
  }
}

// ============================================================================
// Application Repository
// ============================================================================

export const applicationRepository = {
  async getAll(): Promise<JobApplication[]> {
    return db.applications.orderBy('appliedDate').reverse().toArray()
  },

  async getById(id: string): Promise<JobApplication | undefined> {
    return db.applications.get(id)
  },

  async getByStage(stage: JobApplication['stage']): Promise<JobApplication[]> {
    return db.applications.where('stage').equals(stage).toArray()
  },

  async getActive(): Promise<JobApplication[]> {
    return db.applications.where('status').equals('active').toArray()
  },

  async getFollowUpsDue(date: Date): Promise<JobApplication[]> {
    const dateStr = date.toISOString().split('T')[0]
    return db.applications
      .where('followUpDate')
      .belowOrEqual(dateStr)
      .filter(app => app.status === 'active')
      .toArray()
  },

  async save(application: JobApplication): Promise<string> {
    application.updatedAt = new Date()
    await db.applications.put(application)
    return application.id
  },

  async create(application: Omit<JobApplication, 'id' | 'createdAt' | 'updatedAt'>): Promise<string> {
    const now = new Date()
    const newApp: JobApplication = {
      ...application,
      id: crypto.randomUUID(),
      createdAt: now,
      updatedAt: now
    }
    await db.applications.add(newApp)
    return newApp.id
  },

  async delete(id: string): Promise<void> {
    await db.applications.delete(id)
  },

  async updateStage(id: string, stage: JobApplication['stage']): Promise<void> {
    await db.applications.update(id, { stage, updatedAt: new Date() })
  },

  async updateFollowUpDate(id: string, followUpDate: string | undefined): Promise<void> {
    await db.applications.update(id, { followUpDate, updatedAt: new Date() })
  }
}

// ============================================================================
// Notification Repository
// ============================================================================

export const notificationRepository = {
  async getAll(): Promise<Notification[]> {
    return db.notifications.orderBy('createdAt').reverse().toArray()
  },

  async getUnread(): Promise<Notification[]> {
    return db.notifications
      .where('[userId+readAt]')
      .between(['', ''], ['', '\uffff'])  // readAt is null (empty string in indexeddb)
      .toArray()
      .then(items => items.filter(n => n.readAt === null))
  },

  async getUnreadCount(): Promise<number> {
    const all = await db.notifications.toArray()
    return all.filter(n => n.readAt === null).length
  },

  async getScheduledDue(date: Date): Promise<Notification[]> {
    return db.notifications
      .where('scheduledFor')
      .belowOrEqual(date)
      .filter(n => n.readAt === null && n.scheduledFor !== null)
      .toArray()
  },

  async getById(id: string): Promise<Notification | undefined> {
    return db.notifications.get(id)
  },

  async create(notification: Omit<Notification, 'id' | 'createdAt' | 'updatedAt'>): Promise<string> {
    const now = new Date()
    const newNotification: Notification = {
      ...notification,
      id: crypto.randomUUID(),
      createdAt: now,
      updatedAt: now
    }
    await db.notifications.add(newNotification)
    return newNotification.id
  },

  async markRead(id: string): Promise<void> {
    await db.notifications.update(id, { readAt: new Date(), updatedAt: new Date() })
  },

  async markAllRead(): Promise<void> {
    const unread = await this.getUnread()
    const now = new Date()
    await Promise.all(
      unread.map(n => db.notifications.update(n.id, { readAt: now, updatedAt: now }))
    )
  },

  async dismiss(id: string): Promise<void> {
    await db.notifications.update(id, { dismissedAt: new Date(), updatedAt: new Date() })
  },

  async delete(id: string): Promise<void> {
    await db.notifications.delete(id)
  },

  async clearAll(): Promise<void> {
    await db.notifications.clear()
  }
}

// ============================================================================
// Settings Repository
// ============================================================================

export const settingsRepository = {
  async get(): Promise<AppSettings> {
    const settings = await db.settings.get('default')
    return settings || {
      notifications: { enabled: true, followUpReminderDays: 7 },
      autofill: { autoSubmit: false, confirmBeforeFill: true },
      theme: 'system'
    }
  },

  async save(settings: AppSettings): Promise<void> {
    await db.settings.put({ ...settings, id: 'default' })
  }
}

// ============================================================================
// Sync Queue Repository
// ============================================================================

export const syncQueueRepository = {
  async getAll(): Promise<SyncQueueItem[]> {
    return db.syncQueue.orderBy('createdAt').toArray()
  },

  async getCount(): Promise<number> {
    return db.syncQueue.count()
  },

  async add(item: Omit<SyncQueueItem, 'id' | 'createdAt' | 'retryCount'>): Promise<number> {
    return db.syncQueue.add({
      ...item,
      createdAt: new Date(),
      retryCount: 0
    }) as Promise<number>
  },

  async incrementRetry(id: number, error: string): Promise<void> {
    const item = await db.syncQueue.get(id)
    if (item) {
      await db.syncQueue.update(id, {
        retryCount: item.retryCount + 1,
        lastError: error
      })
    }
  },

  async remove(id: number): Promise<void> {
    await db.syncQueue.delete(id)
  },

  async clear(): Promise<void> {
    await db.syncQueue.clear()
  }
}

// ============================================================================
// Sync Status Repository
// ============================================================================

export const syncStatusRepository = {
  async get(): Promise<SyncStatus> {
    const status = await db.syncStatus.get('default')
    return status || {
      lastSyncAt: null,
      syncInProgress: false,
      syncEnabled: false,
      pendingChanges: 0,
      lastError: null
    }
  },

  async update(updates: Partial<SyncStatus>): Promise<void> {
    const current = await this.get()
    await db.syncStatus.put({ ...current, ...updates, id: 'default' })
  },

  async setSyncEnabled(enabled: boolean): Promise<void> {
    await this.update({ syncEnabled: enabled })
  },

  async setSyncInProgress(inProgress: boolean): Promise<void> {
    await this.update({ syncInProgress: inProgress })
  },

  async recordSync(success: boolean, error?: string): Promise<void> {
    await this.update({
      lastSyncAt: success ? new Date() : undefined,
      syncInProgress: false,
      lastError: error || null
    })
  }
}

// ============================================================================
// User Authentication Types
// ============================================================================

export interface UserProfile {
  id: string
  email: string
  displayName: string | null
  avatarUrl: string | null
  syncEnabled: boolean
  lastSyncAt: Date | null
  createdAt: Date
  updatedAt: Date
}

export interface UserSettings {
  userId: string

  // Notification preferences
  notificationsEnabled: boolean
  followUpReminderDays: number
  emailNotifications: boolean
  pushNotifications: boolean

  // Autofill preferences
  autoSubmit: boolean
  confirmBeforeFill: boolean

  // Theme
  theme: 'light' | 'dark' | 'system'

  createdAt: Date
  updatedAt: Date
}

// Auth state for the app
export interface AuthState {
  user: UserProfile | null
  session: Session | null
  isLoading: boolean
  isAuthenticated: boolean
}

// Supabase session (simplified)
export interface Session {
  accessToken: string
  refreshToken: string
  expiresAt: number
  user: {
    id: string
    email: string
  }
}

// ============================================================================
// Notification Types
// ============================================================================

export type NotificationType = 
  | 'follow_up_reminder'
  | 'application_update'
  | 'interview_scheduled'
  | 'offer_received'
  | 'reminder_custom'
  | 'system'

export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent'

export interface Notification {
  id: string
  userId: string

  // Content
  type: NotificationType
  priority: NotificationPriority
  title: string
  message: string

  // Related entity
  entityType: string | null  // 'application', 'profile', etc.
  entityId: string | null

  // Action
  actionUrl: string | null
  actionLabel: string | null

  // Scheduling
  scheduledFor: Date | null

  // Delivery status
  readAt: Date | null
  dismissedAt: Date | null
  emailSentAt: Date | null
  pushSentAt: Date | null

  createdAt: Date
  updatedAt: Date
}

// For creating new notifications
export interface CreateNotificationInput {
  type: NotificationType
  priority?: NotificationPriority
  title: string
  message: string
  entityType?: string
  entityId?: string
  actionUrl?: string
  actionLabel?: string
  scheduledFor?: Date
}

// For displaying in UI
export interface NotificationGroup {
  date: string  // 'Today', 'Yesterday', 'This Week', etc.
  notifications: Notification[]
}

// ============================================================================
// Cloud Sync Types
// ============================================================================

export interface SyncStatus {
  lastSyncAt: Date | null
  syncInProgress: boolean
  syncEnabled: boolean
  pendingChanges: number
  lastError: string | null
}

export interface SyncResult {
  success: boolean
  syncedAt: Date
  applicationsSynced: number
  profilesSynced: number
  errors: SyncError[]
}

export interface SyncError {
  entity: string
  entityId: string
  error: string
}

import { create } from 'zustand'
import { persist } from 'zustand/middleware'
import type { UserProfile, Session, UserSettings } from '../types/auth'
import { authService, settingsService } from '../storage/supabase'

interface AuthState {
  user: UserProfile | null
  session: Session | null
  settings: UserSettings | null
  isLoading: boolean
  isAuthenticated: boolean
  error: string | null
}

interface AuthActions {
  signIn: (email: string, password: string) => Promise<void>
  signUp: (email: string, password: string, displayName?: string) => Promise<void>
  signInWithOAuth: (provider: 'google' | 'github') => Promise<void>
  signOut: () => Promise<void>
  refreshSession: () => Promise<void>
  updateProfile: (updates: Partial<Pick<UserProfile, 'displayName' | 'avatarUrl' | 'syncEnabled'>>) => Promise<void>
  updateSettings: (updates: Partial<Omit<UserSettings, 'userId' | 'createdAt' | 'updatedAt'>>) => Promise<void>
  clearError: () => void
  setLoading: (loading: boolean) => void
}

export const useAuthStore = create<AuthState & AuthActions>()(
  persist(
    (set, get) => ({
      // State
      user: null,
      session: null,
      settings: null,
      isLoading: true,
      isAuthenticated: false,
      error: null,

      // Actions
      signIn: async (email: string, password: string) => {
        set({ isLoading: true, error: null })

        const result = await authService.signIn(email, password)

        if (result.success) {
          await get().refreshSession()
        } else {
          set({ error: result.error, isLoading: false })
        }
      },

      signUp: async (email: string, password: string, displayName?: string) => {
        set({ isLoading: true, error: null })

        const result = await authService.signUp(email, password, displayName)

        if (result.success) {
          // For email confirmation, don't auto-login
          set({ isLoading: false })
        } else {
          set({ error: result.error, isLoading: false })
        }
      },

      signInWithOAuth: async (provider: 'google' | 'github') => {
        set({ isLoading: true, error: null })

        const result = await authService.signInWithOAuth(provider)

        if (!result.success) {
          set({ error: result.error, isLoading: false })
        }
        // OAuth will redirect, so we don't update state here
      },

      signOut: async () => {
        set({ isLoading: true })
        await authService.signOut()
        set({
          user: null,
          session: null,
          settings: null,
          isAuthenticated: false,
          isLoading: false
        })
      },

      refreshSession: async () => {
        set({ isLoading: true })

        try {
          const [session, profile, settings] = await Promise.all([
            authService.getSession(),
            authService.getProfile(),
            settingsService.get()
          ])

          set({
            session,
            user: profile,
            settings,
            isAuthenticated: !!session && !!profile,
            isLoading: false,
            error: null
          })
        } catch (error) {
          set({
            session: null,
            user: null,
            settings: null,
            isAuthenticated: false,
            isLoading: false,
            error: 'Failed to refresh session'
          })
        }
      },

      updateProfile: async (updates) => {
        const result = await authService.updateProfile(updates)

        if (result.success) {
          const current = get().user
          if (current) {
            set({
              user: { ...current, ...updates }
            })
          }
        } else {
          set({ error: result.error })
        }
      },

      updateSettings: async (updates) => {
        const result = await settingsService.update(updates)

        if (result.success) {
          const current = get().settings
          if (current) {
            set({
              settings: { ...current, ...updates }
            })
          }
        } else {
          set({ error: result.error })
        }
      },

      clearError: () => set({ error: null }),

      setLoading: (loading: boolean) => set({ isLoading: loading })
    }),
    {
      name: 'jobflow-auth',
      partialize: (state) => ({
        session: state.session
      })
    }
  )
)

// Subscribe to auth state changes
export function initializeAuth() {
  const { refreshSession } = useAuthStore.getState()

  // Initial session check
  refreshSession()

  // Listen for auth changes
  authService.onAuthStateChange((event, _session) => {
    if (event === 'SIGNED_IN' || event === 'TOKEN_REFRESHED') {
      refreshSession()
    } else if (event === 'SIGNED_OUT') {
      useAuthStore.setState({
        user: null,
        session: null,
        settings: null,
        isAuthenticated: false
      })
    }
  })
}

