// ============================================================================
// React Hooks - Applications
// Easy-to-use hooks for job application management
// ============================================================================

import { useState, useEffect, useCallback, useMemo } from 'react'
import { 
  applicationsApi, 
  type CreateApplicationInput, 
  type UpdateApplicationInput,
  type ApplicationFilters 
} from '../api/applications.api'
import type { JobApplication, PipelineStage } from '../types'

// ============================================================================
// useApplications Hook
// ============================================================================

export interface UseApplicationsOptions {
  filters?: ApplicationFilters
  autoRefresh?: boolean
  refreshInterval?: number
}

export interface UseApplicationsReturn {
  // State
  applications: JobApplication[]
  isLoading: boolean
  error: string | null

  // Actions
  create: (input: CreateApplicationInput) => Promise<JobApplication>
  update: (id: string, updates: UpdateApplicationInput) => Promise<JobApplication>
  remove: (id: string) => Promise<void>
  moveToStage: (id: string, stage: PipelineStage) => Promise<JobApplication>
  setFollowUpDate: (id: string, date: string | undefined) => Promise<void>
  refresh: () => Promise<void>
  clearError: () => void

  // Computed
  stats: ApplicationStats
  byStage: Record<PipelineStage, JobApplication[]>
}

export interface ApplicationStats {
  total: number
  active: number
  upcomingFollowUps: number
  thisWeek: number
  thisMonth: number
}

export function useApplications(options: UseApplicationsOptions = {}): UseApplicationsReturn {
  const [applications, setApplications] = useState<JobApplication[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const loadApplications = useCallback(async () => {
    setIsLoading(true)
    try {
      const data = options.filters
        ? await applicationsApi.getFiltered(options.filters)
        : await applicationsApi.getAll()
      setApplications(data)
      setError(null)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load applications')
    } finally {
      setIsLoading(false)
    }
  }, [options.filters])

  useEffect(() => {
    loadApplications()
  }, [loadApplications])

  // Auto-refresh
  useEffect(() => {
    if (!options.autoRefresh || !options.refreshInterval) return

    const interval = setInterval(loadApplications, options.refreshInterval)
    return () => clearInterval(interval)
  }, [loadApplications, options.autoRefresh, options.refreshInterval])

  const create = useCallback(async (input: CreateApplicationInput) => {
    const application = await applicationsApi.create(input)
    setApplications(prev => [application, ...prev])
    return application
  }, [])

  const update = useCallback(async (id: string, updates: UpdateApplicationInput) => {
    const application = await applicationsApi.update(id, updates)
    setApplications(prev => prev.map(a => a.id === id ? application : a))
    return application
  }, [])

  const remove = useCallback(async (id: string) => {
    await applicationsApi.delete(id)
    setApplications(prev => prev.filter(a => a.id !== id))
  }, [])

  const moveToStage = useCallback(async (id: string, stage: PipelineStage) => {
    const application = await applicationsApi.moveToStage(id, stage)
    setApplications(prev => prev.map(a => a.id === id ? application : a))
    return application
  }, [])

  const setFollowUpDate = useCallback(async (id: string, date: string | undefined) => {
    await applicationsApi.setFollowUpDate(id, date)
    setApplications(prev => prev.map(a => 
      a.id === id ? { ...a, followUpDate: date } : a
    ))
  }, [])

  const clearError = useCallback(() => setError(null), [])

  // Computed values
  const byStage = useMemo((): Record<PipelineStage, JobApplication[]> => {
    const stages: PipelineStage[] = ['applied', 'interviewing', 'offer', 'rejected', 'closed']
    return stages.reduce((acc, stage) => {
      acc[stage] = applications.filter(a => a.stage === stage && a.status === 'active')
      return acc
    }, {} as Record<PipelineStage, JobApplication[]>)
  }, [applications])

  const stats = useMemo((): ApplicationStats => {
    const now = new Date()
    const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000)
    const monthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000)
    const today = now.toISOString().split('T')[0]

    return {
      total: applications.length,
      active: applications.filter(a => a.status === 'active').length,
      upcomingFollowUps: applications.filter(
        a => a.followUpDate && a.followUpDate <= today && a.status === 'active'
      ).length,
      thisWeek: applications.filter(
        a => a.appliedDate >= weekAgo.toISOString().split('T')[0]
      ).length,
      thisMonth: applications.filter(
        a => a.appliedDate >= monthAgo.toISOString().split('T')[0]
      ).length
    }
  }, [applications])

  return {
    applications,
    isLoading,
    error,
    create,
    update,
    remove,
    moveToStage,
    setFollowUpDate,
    refresh: loadApplications,
    clearError,
    stats,
    byStage
  }
}

// ============================================================================
// useApplication Hook
// ============================================================================

export interface UseApplicationReturn {
  application: JobApplication | null
  isLoading: boolean
  error: string | null
  update: (updates: UpdateApplicationInput) => Promise<void>
  moveToStage: (stage: PipelineStage) => Promise<void>
  setFollowUpDate: (date: string | undefined) => Promise<void>
  remove: () => Promise<void>
}

export function useApplication(id: string): UseApplicationReturn {
  const [application, setApplication] = useState<JobApplication | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    const load = async () => {
      setIsLoading(true)
      try {
        const data = await applicationsApi.getById(id)
        setApplication(data || null)
        setError(null)
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load application')
      } finally {
        setIsLoading(false)
      }
    }

    if (id) load()
  }, [id])

  const update = useCallback(async (updates: UpdateApplicationInput) => {
    if (!application) return
    const updated = await applicationsApi.update(id, updates)
    setApplication(updated)
  }, [id, application])

  const moveToStage = useCallback(async (stage: PipelineStage) => {
    const updated = await applicationsApi.moveToStage(id, stage)
    setApplication(updated)
  }, [id])

  const setFollowUpDate = useCallback(async (date: string | undefined) => {
    await applicationsApi.setFollowUpDate(id, date)
    setApplication(prev => prev ? { ...prev, followUpDate: date } : null)
  }, [id])

  const remove = useCallback(async () => {
    await applicationsApi.delete(id)
    setApplication(null)
  }, [id])

  return {
    application,
    isLoading,
    error,
    update,
    moveToStage,
    setFollowUpDate,
    remove
  }
}

// ============================================================================
// useApplicationStats Hook
// ============================================================================

export function useApplicationStats(): {
  stats: ApplicationStats | null
  isLoading: boolean
  error: string | null
  refresh: () => Promise<void>
} {
  const [stats, setStats] = useState<ApplicationStats | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const loadStats = useCallback(async () => {
    setIsLoading(true)
    try {
      const data = await applicationsApi.getStats()
      setStats(data)
      setError(null)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load stats')
    } finally {
      setIsLoading(false)
    }
  }, [])

  useEffect(() => {
    loadStats()
  }, [loadStats])

  return {
    stats,
    isLoading,
    error,
    refresh: loadStats
  }
}

// ============================================================================
// Applications API - Job Application Management
// Handles CRUD operations for job applications with local-first storage
// and optional cloud sync
// ============================================================================

import { applicationRepository, syncQueueRepository } from '../storage/db'
import { authApi } from './auth.api'
import type { JobApplication, ApplicationStatus, PipelineStage } from '../types'

// ============================================================================
// Types
// ============================================================================

export interface CreateApplicationInput {
  company: string
  position: string
  source: string
  sourceUrl?: string
  appliedDate: string
  status?: ApplicationStatus
  stage?: PipelineStage
  followUpDate?: string
  notes?: string
  salary?: {
    amount: number
    currency: string
    frequency: 'hourly' | 'yearly'
  }
}

export interface UpdateApplicationInput {
  company?: string
  position?: string
  source?: string
  sourceUrl?: string
  appliedDate?: string
  status?: ApplicationStatus
  stage?: PipelineStage
  followUpDate?: string
  notes?: string
  salary?: {
    amount: number
    currency: string
    frequency: 'hourly' | 'yearly'
  }
}

export interface ApplicationFilters {
  status?: ApplicationStatus
  stage?: PipelineStage
  company?: string
  search?: string
  dateFrom?: string
  dateTo?: string
}

// ============================================================================
// Applications API
// ============================================================================

export const applicationsApi = {
  // ---------------------------------------------------------------------------
  // CRUD Operations (Local-First)
  // ---------------------------------------------------------------------------

  /**
   * Get all applications
   */
  async getAll(): Promise<JobApplication[]> {
    return applicationRepository.getAll()
  },

  /**
   * Get application by ID
   */
  async getById(id: string): Promise<JobApplication | undefined> {
    return applicationRepository.getById(id)
  },

  /**
   * Get applications by stage
   */
  async getByStage(stage: PipelineStage): Promise<JobApplication[]> {
    return applicationRepository.getByStage(stage)
  },

  /**
   * Get active applications
   */
  async getActive(): Promise<JobApplication[]> {
    return applicationRepository.getActive()
  },

  /**
   * Get applications with follow-ups due
   */
  async getFollowUpsDue(date?: Date): Promise<JobApplication[]> {
    return applicationRepository.getFollowUpsDue(date || new Date())
  },

  /**
   * Get applications with filters
   */
  async getFiltered(filters: ApplicationFilters): Promise<JobApplication[]> {
    let applications = await this.getAll()

    if (filters.status) {
      applications = applications.filter(a => a.status === filters.status)
    }

    if (filters.stage) {
      applications = applications.filter(a => a.stage === filters.stage)
    }

    if (filters.company) {
      applications = applications.filter(a =>
        a.company.toLowerCase().includes(filters.company!.toLowerCase())
      )
    }

    if (filters.search) {
      const search = filters.search.toLowerCase()
      applications = applications.filter(a =>
        a.company.toLowerCase().includes(search) ||
        a.position.toLowerCase().includes(search) ||
        (a.notes && a.notes.toLowerCase().includes(search))
      )
    }

    if (filters.dateFrom) {
      applications = applications.filter(a => a.appliedDate >= filters.dateFrom!)
    }

    if (filters.dateTo) {
      applications = applications.filter(a => a.appliedDate <= filters.dateTo!)
    }

    return applications
  },

  /**
   * Create a new application
   */
  async create(input: CreateApplicationInput): Promise<JobApplication> {
    const id = await applicationRepository.create({
      company: input.company,
      position: input.position,
      source: input.source,
      sourceUrl: input.sourceUrl,
      appliedDate: input.appliedDate,
      status: input.status || 'active',
      stage: input.stage || 'applied',
      followUpDate: input.followUpDate,
      notes: input.notes || '',
      contacts: [],
      salary: input.salary
    })

    const application = await applicationRepository.getById(id)
    if (!application) {
      throw new Error('Failed to create application')
    }

    // Queue for sync if authenticated
    await this.queueSync(application.id, 'create')

    return application
  },

  /**
   * Update an application
   */
  async update(id: string, updates: UpdateApplicationInput): Promise<JobApplication> {
    const application = await applicationRepository.getById(id)
    if (!application) {
      throw new Error(`Application ${id} not found`)
    }

    await applicationRepository.save({
      ...application,
      ...updates
    })

    const updated = await applicationRepository.getById(id)
    if (!updated) {
      throw new Error('Failed to update application')
    }

    // Queue for sync if authenticated
    await this.queueSync(id, 'update')

    return updated
  },

  /**
   * Delete an application
   */
  async delete(id: string): Promise<void> {
    await applicationRepository.delete(id)

    // Queue for sync if authenticated
    await this.queueSync(id, 'delete')
  },

  // ---------------------------------------------------------------------------
  // Stage Management
  // ---------------------------------------------------------------------------

  /**
   * Move application to a new stage
   */
  async moveToStage(id: string, stage: PipelineStage): Promise<JobApplication> {
    await applicationRepository.updateStage(id, stage)
    const application = await applicationRepository.getById(id)
    if (!application) {
      throw new Error(`Application ${id} not found`)
    }

    // Queue for sync
    await this.queueSync(id, 'update')

    return application
  },

  /**
   * Set follow-up date
   */
  async setFollowUpDate(id: string, date: string | undefined): Promise<void> {
    await applicationRepository.updateFollowUpDate(id, date)
    await this.queueSync(id, 'update')
  },

  // ---------------------------------------------------------------------------
  // Statistics
  // ---------------------------------------------------------------------------

  /**
   * Get application statistics
   */
  async getStats(): Promise<{
    total: number
    active: number
    byStage: Record<PipelineStage, number>
    upcomingFollowUps: number
    thisWeek: number
    thisMonth: number
  }> {
    const applications = await this.getAll()
    const now = new Date()
    const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000)
    const monthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000)
    const today = now.toISOString().split('T')[0]

    const byStage: Record<PipelineStage, number> = {
      applied: 0,
      interviewing: 0,
      offer: 0,
      rejected: 0,
      closed: 0
    }

    let upcomingFollowUps = 0

    for (const app of applications) {
      if (app.status === 'active') {
        byStage[app.stage]++
      }
      if (app.followUpDate && app.followUpDate <= today && app.status === 'active') {
        upcomingFollowUps++
      }
    }

    return {
      total: applications.length,
      active: applications.filter(a => a.status === 'active').length,
      byStage,
      upcomingFollowUps,
      thisWeek: applications.filter(a => a.appliedDate >= weekAgo.toISOString().split('T')[0]).length,
      thisMonth: applications.filter(a => a.appliedDate >= monthAgo.toISOString().split('T')[0]).length
    }
  },

  // ---------------------------------------------------------------------------
  // Sync Helper
  // ---------------------------------------------------------------------------

  /**
   * Queue an application for cloud sync
   */
  async queueSync(id: string, action: 'create' | 'update' | 'delete'): Promise<void> {
    const isAuthenticated = await authApi.isAuthenticated()
    if (!isAuthenticated) return

    const application = action !== 'delete' ? await this.getById(id) : undefined

    await syncQueueRepository.add({
      entityType: 'application',
      entityId: id,
      action,
      payload: application ? { ...application } as unknown as Record<string, unknown> : { id }
    })
  }
}

