import { describe, it, expect } from 'vitest'
import type { 
  UserProfile, 
  JobApplication, 
  PipelineStage, 
  ApplicationStatus,
  AppSettings,
  FormSchema,
  FieldMapping
} from '../types'

describe('Core Types', () => {
