// ============================================================================

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { renderHook, act, waitFor } from '@testing-library/react'
import { useApplications, useApplication, useApplicationStats } from './useApplications'

// Mock the API
vi.mock('./applications.api', () => ({
  applicationsApi: {
    getAll: vi.fn(),
    getFiltered: vi.fn(),
    getById: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    delete: vi.fn(),
    moveToStage: vi.fn(),
    setFollowUpDate: vi.fn(),
    getStats: vi.fn()
  },
  type CreateApplicationInput: {},
  type UpdateApplicationInput: {},
  type ApplicationFilters: {}
}))

import { applicationsApi } from './applications.api'

const mockApi = applicationsApi as ReturnType<typeof vi.fn>

describe('useApplications Hook', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('should load applications on mount', async () => {
    const mockApps = [
      {
        id: 'app-1',
        company: 'Tech Corp',
        position: 'Engineer',
        source: 'LinkedIn',
        appliedDate: '2024-01-01',
        status: 'active' as const,
        stage: 'applied' as const,
        notes: '',
        contacts: [],
        createdAt: new Date(),
        updatedAt: new Date()
      }
    ]

    mockApi.getAll.mockResolvedValue(mockApps)

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.applications).toHaveLength(1)
    })

    expect(result.current.applications[0].company).toBe('Tech Corp')
    expect(result.current.isLoading).toBe(false)
  })

  it('should handle loading state', () => {
    mockApi.getAll.mockImplementation(() => new Promise(() => {})) // Never resolves

    const { result } = renderHook(() => useApplications())

    expect(result.current.isLoading).toBe(true)
  })

  it('should handle errors', async () => {
    mockApi.getAll.mockRejectedValue(new Error('Failed to load'))

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.error).toBe('Failed to load')
    })

    expect(result.current.isLoading).toBe(false)
  })

  it('should create new application', async () => {
    const mockApps: any[] = []
    mockApi.getAll.mockResolvedValue(mockApps)

    const newApp = {
      id: 'new-app',
      company: 'New Corp',
      position: 'Engineer',
      source: 'LinkedIn',
      appliedDate: '2024-02-01',
      status: 'active' as const,
      stage: 'applied' as const,
      notes: '',
      contacts: [],
      createdAt: new Date(),
      updatedAt: new Date()
    }

    mockApi.create.mockResolvedValue(newApp)

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    await act(async () => {
      await result.current.create({
        company: 'New Corp',
        position: 'Engineer',
        source: 'LinkedIn',
        appliedDate: '2024-02-01'
      })
    })

    expect(mockApi.create).toHaveBeenCalled()
  })

  it('should update application', async () => {
    const mockApps = [
      {
        id: 'app-1',
        company: 'Tech Corp',
        position: 'Engineer',
        source: 'LinkedIn',
        appliedDate: '2024-01-01',
        status: 'active' as const,
        stage: 'applied' as const,
        notes: '',
        contacts: [],
        createdAt: new Date(),
        updatedAt: new Date()
      }
    ]

    mockApi.getAll.mockResolvedValue(mockApps)

    const updatedApp = { ...mockApps[0], notes: 'Updated notes' }
    mockApi.update.mockResolvedValue(updatedApp)

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.applications).toHaveLength(1)
    })

    await act(async () => {
      await result.current.update('app-1', { notes: 'Updated notes' })
    })

    expect(mockApi.update).toHaveBeenCalledWith('app-1', { notes: 'Updated notes' })
  })

  it('should delete application', async () => {
    const mockApps = [
      {
        id: 'app-1',
        company: 'Tech Corp',
        position: 'Engineer',
        source: 'LinkedIn',
        appliedDate: '2024-01-01',
        status: 'active' as const,
        stage: 'applied' as const,
        notes: '',
        contacts: [],
        createdAt: new Date(),
        updatedAt: new Date()
      }
    ]

    mockApi.getAll.mockResolvedValue(mockApps)
    mockApi.delete.mockResolvedValue()

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.applications).toHaveLength(1)
    })

    await act(async () => {
      await result.current.remove('app-1')
    })

    expect(mockApi.delete).toHaveBeenCalledWith('app-1')
  })

  it('should calculate stats correctly', async () => {
    const today = new Date().toISOString().split('T')[0]
    const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0]

    const mockApps = [
      { id: '1', company: 'A', position: 'P', source: 'S', appliedDate: today, status: 'active' as const, stage: 'applied' as const, notes: '', contacts: [], followUpDate: today, createdAt: new Date(), updatedAt: new Date() },
      { id: '2', company: 'B', position: 'P', source: 'S', appliedDate: weekAgo, status: 'active' as const, stage: 'interviewing' as const, notes: '', contacts: [], createdAt: new Date(), updatedAt: new Date() },
      { id: '3', company: 'C', position: 'P', source: 'S', appliedDate: weekAgo, status: 'archived' as const, stage: 'applied' as const, notes: '', contacts: [], createdAt: new Date(), updatedAt: new Date() }
    ]

    mockApi.getAll.mockResolvedValue(mockApps)

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    expect(result.current.stats.total).toBe(3)
    expect(result.current.stats.active).toBe(2)
    expect(result.current.stats.upcomingFollowUps).toBe(1)
  })

  it('should group applications by stage', async () => {
    const mockApps = [
      { id: '1', company: 'A', position: 'P', source: 'S', appliedDate: '2024-01-01', status: 'active' as const, stage: 'applied' as const, notes: '', contacts: [], createdAt: new Date(), updatedAt: new Date() },
      { id: '2', company: 'B', position: 'P', source: 'S', appliedDate: '2024-01-01', status: 'active' as const, stage: 'interviewing' as const, notes: '', contacts: [], createdAt: new Date(), updatedAt: new Date() },
      { id: '3', company: 'C', position: 'P', source: 'S', appliedDate: '2024-01-01', status: 'active' as const, stage: 'applied' as const, notes: '', contacts: [], createdAt: new Date(), updatedAt: new Date() }
    ]

    mockApi.getAll.mockResolvedValue(mockApps)

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    expect(result.current.byStage.applied).toHaveLength(2)
    expect(result.current.byStage.interviewing).toHaveLength(1)
    expect(result.current.byStage.offer).toHaveLength(0)
  })

  it('should filter by stage in byStage grouping', async () => {
    const mockApps = [
      { id: '1', company: 'A', position: 'P', source: 'S', appliedDate: '2024-01-01', status: 'active' as const, stage: 'applied' as const, notes: '', contacts: [], createdAt: new Date(), updatedAt: new Date() },
      { id: '2', company: 'B', position: 'P', source: 'S', appliedDate: '2024-01-01', status: 'archived' as const, stage: 'applied' as const, notes: '', contacts: [], createdAt: new Date(), updatedAt: new Date() }
    ]

    mockApi.getAll.mockResolvedValue(mockApps)

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    // Should only include active applications
    expect(result.current.byStage.applied).toHaveLength(1)
  })

  it('should support moving to stage', async () => {
    const mockApps = [
      { id: 'app-1', company: 'A', position: 'P', source: 'S', appliedDate: '2024-01-01', status: 'active' as const, stage: 'applied' as const, notes: '', contacts: [], createdAt: new Date(), updatedAt: new Date() }
    ]

    mockApi.getAll.mockResolvedValue(mockApps)
    mockApi.moveToStage.mockResolvedValue({ ...mockApps[0], stage: 'interviewing' as const })

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.applications).toHaveLength(1)
    })

    await act(async () => {
      await result.current.moveToStage('app-1', 'interviewing')
    })

    expect(mockApi.moveToStage).toHaveBeenCalledWith('app-1', 'interviewing')
  })

  it('should support setting follow-up date', async () => {
    const mockApps = [
      { id: 'app-1', company: 'A', position: 'P', source: 'S', appliedDate: '2024-01-01', status: 'active' as const, stage: 'applied' as const, notes: '', contacts: [], createdAt: new Date(), updatedAt: new Date() }
    ]

    mockApi.getAll.mockResolvedValue(mockApps)
    mockApi.setFollowUpDate.mockResolvedValue()

    const { result } = renderHook(() => useApplications())

    await waitFor(() => {
      expect(result.current.applications).toHaveLength(1)
    })

    await act(async () => {
      await result.current.setFollowUpDate('app-1', '2024-02-01')
    })

    expect(mockApi.setFollowUpDate).toHaveBeenCalledWith('app-1', '2024-02-01')
  })
})

describe('useApplication Hook', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('should load single application by ID', async () => {
    const mockApp = {
      id: 'app-1',
      company: 'Tech Corp',
      position: 'Engineer',
      source: 'LinkedIn',
      appliedDate: '2024-01-01',
      status: 'active' as const,
      stage: 'applied' as const,
      notes: '',
      contacts: [],
      createdAt: new Date(),
      updatedAt: new Date()
    }

    mockApi.getById.mockResolvedValue(mockApp)

    const { result } = renderHook(() => useApplication('app-1'))

    await waitFor(() => {
      expect(result.current.application).toBeDefined()
    })

    expect(result.current.application?.company).toBe('Tech Corp')
  })

  it('should return null for non-existent application', async () => {
    mockApi.getById.mockResolvedValue(undefined)

    const { result } = renderHook(() => useApplication('non-existent'))

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })

    expect(result.current.application).toBeNull()
  })
})

describe('useApplicationStats Hook', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('should load stats', async () => {
    const mockStats = {
      total: 10,
      active: 5,
      byStage: { applied: 2, interviewing: 2, offer: 1, rejected: 0, closed: 0 } as any,
      upcomingFollowUps: 3,
      thisWeek: 2,
      thisMonth: 5
    }

    mockApi.getStats.mockResolvedValue(mockStats)

    const { result } = renderHook(() => useApplicationStats())

    await waitFor(() => {
      expect(result.current.stats).toBeDefined()
    })

    expect(result.current.stats?.total).toBe(10)
    expect(result.current.stats?.active).toBe(5)
    expect(result.current.stats?.upcomingFollowUps).toBe(3)
  })
})

