function mockSupabase(page: import('@playwright/test').Page) {
  // Abort realtime
  page.route('**/realtime/**', route => route.abort());

  // Mock REST endpoints
  page.route('**/rest/v1/**', (route) => {
    const url = route.request().url();

    // Tasks
    if (url.includes('/rest/v1/tasks')) {
      if (route.request().method() === 'POST') {
        // Creating follow-up tasks
        return route.fulfill({
          status: 200,
          contentType: 'application/json',
          body: JSON.stringify({
            ...DONE_TASK,
            id: `task-followup-${Date.now()}`,
            status: 'backlog',
            title: 'Follow-up task',
          }),
        });
      }
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([DONE_TASK]),
      });
    }

    // Agents
    if (url.includes('/rest/v1/agents')) {
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify(AGENTS),
      });
    }

    // Task activity
    if (url.includes('/rest/v1/task_activity')) {
      if (route.request().method() === 'POST') {
        return route.fulfill({
          status: 200,
          contentType: 'application/json',
          body: JSON.stringify({ id: 'ta-new', ...TASK_ACTIVITY }),
        });
      }
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([TASK_ACTIVITY]),
      });
    }

    // Agent activity
    if (url.includes('/rest/v1/agent_activity')) {
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([FAILED_AGENT_ACTIVITY]),
      });
    }

    // Anchored comments
    if (url.includes('/rest/v1/anchored_comments')) {
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([OPEN_COMMENT]),
      });
    }

    // Channels
    if (url.includes('/rest/v1/channels')) {
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([]),
      });
    }

    // Messages
    if (url.includes('/rest/v1/messages')) {
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([]),
      });
    }

    // Policy profiles
    if (url.includes('/rest/v1/policy_profiles')) {
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([]),
      });
    }

    // Policy assignments
    if (url.includes('/rest/v1/policy_profile_assignments')) {
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([]),
      });
    }

    // Task versions
    if (url.includes('/rest/v1/task_versions')) {
      return route.fulfill({
        status: 200,
        contentType: 'application/json',
        body: JSON.stringify([]),
      });
    }

    // Default empty response
    return route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify([]),
    });
  });
}

test.describe('Follow-Up Detection Panel', () => {
  test('shows follow-up panel for done task and allows bulk approval', async ({ page }) => {
    await mockSupabase(page);
    await page.goto('http://localhost:5199/board');

    // Click on the done task to open detail panel
    await page.getByText('Implement user auth').click();

    // Wait for the follow-up detection panel to appear
    const panel = page.getByTestId('follow-up-detection-panel');
    await expect(panel).toBeVisible({ timeout: 10000 });

    // Should show "Detected Follow-Ups" header
    await expect(panel.getByText('Detected Follow-Ups')).toBeVisible();

    // Should show items (open comment, failed action, risk factor from activity log, and task forecast risk)
    const followUpItems = panel.getByTestId('follow-up-item');
    const count = await followUpItems.count();
    expect(count).toBeGreaterThanOrEqual(2);

    // Open comment should be detected
    await expect(panel.getByText(/Should we use JWT/)).toBeVisible();

    // Failed agent action should be detected
    await expect(panel.getByText(/failed agent action/i)).toBeVisible();

    // Footer should show selected count
    await expect(panel.getByText(/of.*selected/)).toBeVisible();

    // The approve button should be visible
    const approveBtn = panel.getByTestId('follow-up-approve');
    await expect(approveBtn).toBeVisible();
    await expect(approveBtn).toContainText('Add');
    await expect(approveBtn).toContainText('to Backlog');
  });

  test('can deselect items and dismiss the panel', async ({ page }) => {
    await mockSupabase(page);
    await page.goto('http://localhost:5199/board');

    await page.getByText('Implement user auth').click();

    const panel = page.getByTestId('follow-up-detection-panel');
    await expect(panel).toBeVisible({ timeout: 10000 });

    // Click "None" to deselect all
    await panel.getByTestId('follow-up-deselect-all').click();

    // Approve button should show "Add 0 to Backlog"
    await expect(panel.getByTestId('follow-up-approve')).toContainText('Add 0 to Backlog');

    // Click "Select All" to reselect
    await panel.getByTestId('follow-up-select-all').click();

    // Approve button should show count > 0
    const btnText = await panel.getByTestId('follow-up-approve').textContent();
    expect(btnText).not.toContain('Add 0');

    // Dismiss the panel
    await panel.getByTestId('follow-up-dismiss').click();

    // Panel should be gone
    await expect(panel).not.toBeVisible();
  });

  test('shows success message after approving follow-ups', async ({ page }) => {
    await mockSupabase(page);
    await page.goto('http://localhost:5199/board');

    await page.getByText('Implement user auth').click();

    const panel = page.getByTestId('follow-up-detection-panel');
    await expect(panel).toBeVisible({ timeout: 10000 });

    // Click approve
    await panel.getByTestId('follow-up-approve').click();

    // Should show success message
    const successBanner = page.getByTestId('follow-up-success');
    await expect(successBanner).toBeVisible({ timeout: 10000 });
    await expect(successBanner).toContainText('added to backlog');
  });
});

