import { useEffect, useState } from 'react';
import { Plus, X, GitMerge, Play, Square } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { useProjectSchema } from '../../lib/use-project-schema';
import { fetchTasks, fetchAgents, createTask, moveTask, findSimilarItems, suggestDependencies, deleteTask } from '../../lib/api';

import type { SimilarItem } from '../../lib/api';
import { TASK_COLUMNS, PRIORITY_CONFIG } from '../../lib/constants';
import type { Agent, Task, TaskStatus, TaskPriority } from '../../lib/types';
import { TaskCard } from './TaskCard';
import { TaskDetailPanel } from './TaskDetailPanel';
import { TaskForecastPanel } from './TaskForecastPanel';
import { AcceptanceCriteriaPanel } from './AcceptanceCriteriaPanel';
import { DuplicateDetectionPanel } from './DuplicateDetectionPanel';
import { DependencySuggestionPanel } from './DependencySuggestionPanel';
import { GraphView } from './GraphView';
import type { TaskForecast, AcceptanceCriterion } from '../../lib/types';

export function BoardView() {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [agents, setAgents] = useState<Agent[]>([]);
  const [selectedTask, setSelectedTask] = useState<Task | null>(null);
  const [showNewTask, setShowNewTask] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const [newPriority, setNewPriority] = useState<TaskPriority>('medium');
  const [filterPriority, setFilterPriority] = useState<TaskPriority | 'all'>('all');
  const [loading, setLoading] = useState(true);
  const [viewMode, setViewMode] = useState<'kanban' | 'graph'>('kanban');
  const [autoMode, setAutoMode] = useState(false);
  const [showForecast, setShowForecast] = useState(false);
  const [showCriteria, setShowCriteria] = useState(false);
  const [pendingForecast, setPendingForecast] = useState<TaskForecast | null>(null);
  const [duplicates, setDuplicates] = useState<SimilarItem[] | null>(null);
  const [checkingDuplicates, setCheckingDuplicates] = useState(false);
  const [showDepSuggestions, setShowDepSuggestions] = useState(false);
  const [pendingDeps, setPendingDeps] = useState<string[]>([]);

  const projectSchema = useProjectSchema();

  useEffect(() => {
    loadData();
    // Tasks are now stored locally; only subscribe to agent changes via Supabase realtime
    const channel = supabase.channel(`board-agents-realtime-${projectSchema}`)
      .on('postgres_changes', { event: '*', schema: 'public', table: 'agents' }, () => loadAgents())
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, [projectSchema]);

  async function loadData() {
    const [t, a] = await Promise.all([fetchTasks(), fetchAgents()]);
    setTasks(t);
    setAgents(a);
    setLoading(false);
  }

  async function loadAgents() {
    const a = await fetchAgents();
    setAgents(a);
  }

  async function handleRequestForecast() {
    if (!newTitle.trim()) return;
    setCheckingDuplicates(true);
    try {
      const matches = await findSimilarItems(newTitle.trim(), newDesc.trim());
      if (matches.length > 0) {
        setShowNewTask(false);
        setDuplicates(matches);
        setCheckingDuplicates(false);
        return;
      }
    } catch {
      // If duplicate check fails, proceed anyway
    }
    setCheckingDuplicates(false);
    setShowNewTask(false);
    // Check for dependency suggestions before forecast
    const depSuggs = suggestDependencies(newTitle.trim(), newDesc.trim(), tasks);
    if (depSuggs.length > 0) {
      setShowDepSuggestions(true);
    } else {
      setShowForecast(true);
    }
  }

  function handleDuplicateContinue() {
    setDuplicates(null);
    // Check for dependency suggestions before forecast
    const depSuggs = suggestDependencies(newTitle.trim(), newDesc.trim(), tasks);
    if (depSuggs.length > 0) {
      setShowDepSuggestions(true);
    } else {
      setShowForecast(true);
    }
  }

  function handleDepsProceed(selectedDeps: string[]) {
    setPendingDeps(selectedDeps);
    setShowDepSuggestions(false);
    setShowForecast(true);
  }

  function handleDepsSkip() {
    setPendingDeps([]);
    setShowDepSuggestions(false);
    setShowForecast(true);
  }

  async function handleDuplicateLink(item: SimilarItem) {
    setDuplicates(null);
    // Create the task linked to the matched item
    const linkedDesc = `${newDesc.trim()}\n\n---\nLinked to existing ${item.type === 'task' ? 'task' : 'request'}: ${item.id}`;
    await createTask({
      title: newTitle.trim(),
      description: linkedDesc,
      priority: newPriority,
      status: 'backlog',
      created_by: 'Team',
      dependencies: item.type === 'task' ? [item.id] : [],
      partner_request_id: item.type === 'partner_request' ? item.id : null,
    });
    setNewTitle('');
    setNewDesc('');
    setNewPriority('medium');
    loadData();
  }

  function handleProceedWithForecast(forecast: TaskForecast) {
    setPendingForecast(forecast);
    setShowForecast(false);
    setShowCriteria(true);
  }

  async function handleProceedWithCriteria(criteria: AcceptanceCriterion[]) {
    try {
      await createTask({
        title: newTitle.trim(),
        description: newDesc.trim(),
        priority: newPriority,
        status: 'backlog',
        created_by: 'Team',
        forecast: pendingForecast,
        acceptance_criteria: criteria.length > 0 ? criteria : null,
        dependencies: pendingDeps.length > 0 ? pendingDeps : [],
      });
      setNewTitle('');
      setNewDesc('');
      setNewPriority('medium');
      setShowCriteria(false);
      setPendingForecast(null);
      setPendingDeps([]);
      loadData();
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : JSON.stringify(err);
      console.error('createTask failed:', msg);
      alert(`Failed to create task: ${msg}`);
    }
  }

  function handleNarrowScope() {
    setShowForecast(false);
    setShowNewTask(true);
  }

  async function handleDrop(taskId: string, newStatus: TaskStatus) {
    await moveTask(taskId, newStatus, agents);
    loadData();
  }

  function handleDragOver(e: React.DragEvent) {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  }

  function onDrop(e: React.DragEvent, status: TaskStatus) {
    e.preventDefault();
    const taskId = e.dataTransfer.getData('taskId');
    if (taskId) handleDrop(taskId, status);
    const target = e.currentTarget as HTMLElement;
    target.classList.remove('ring-1', 'ring-emerald-500/30');
  }

  function onDragEnter(e: React.DragEvent) {
    e.preventDefault();
    (e.currentTarget as HTMLElement).classList.add('ring-1', 'ring-emerald-500/30');
  }

  function onDragLeave(e: React.DragEvent) {
    (e.currentTarget as HTMLElement).classList.remove('ring-1', 'ring-emerald-500/30');
  }


  const filteredTasks = filterPriority === 'all' ? tasks : tasks.filter(t => t.priority === filterPriority);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="w-8 h-8 border-2 border-emerald-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col">
      <div className="p-4 lg:p-6 pb-0 flex items-center justify-between shrink-0">
        <div>
          <h1 className="text-xl font-bold text-gray-100">Task Board</h1>
          <p className="text-xs text-gray-500 mt-0.5">{tasks.length} tasks total</p>
        </div>
        <div className="flex items-center gap-2">
                      <button
              onClick={async () => {
                const newMode = !autoMode;
                setAutoMode(newMode);
                const { data: channels } = await supabase.from('channels').select('id').eq('name', 'general').limit(1);
                if (channels?.length) {
                  await supabase.from('messages').insert({
                    channel_id: channels[0].id,
                    sender_type: 'human',
                    sender_name: 'User',
                    content: `/automode ${newMode ? 'on' : 'off'}`,
                    message_type: 'text'
                  });
                }
              }}
              className={`px-3 py-1.5 flex items-center gap-1.5 rounded text-xs font-bold transition-all ${autoMode ? 'bg-amber-500/10 text-amber-500 border border-amber-500/20 shadow-[0_0_10px_rgba(245,158,11,0.2)]' : 'bg-gray-800 text-gray-500 hover:text-gray-300'}`}
            >
              {autoMode ? <Square className="w-3 h-3 fill-current" /> : <Play className="w-3 h-3 fill-current" />}
              {autoMode ? 'AUTO-MODE ON' : 'AUTO-MODE'}
            </button>
            <div className="flex items-center gap-1 bg-gray-800/50 rounded-lg p-1 mr-4">
            <button
              onClick={() => setViewMode('kanban')}
              className={`px-3 py-1.5 rounded text-xs transition-colors ${viewMode === 'kanban' ? 'bg-gray-700 text-gray-200' : 'text-gray-500 hover:text-gray-300'}`}
            >Kanban</button>
            <button
              onClick={() => setViewMode('graph')}
              className={`px-3 py-1.5 flex items-center gap-1.5 rounded text-xs transition-colors ${viewMode === 'graph' ? 'bg-gray-700 text-gray-200' : 'text-gray-500 hover:text-gray-300'}`}
            ><GitMerge className="w-3.5 h-3.5" /> Graph Map</button>
          </div>
          <div className="flex items-center gap-1 bg-gray-800/50 rounded-lg p-1">
            <button
              onClick={() => setFilterPriority('all')}
              className={`px-2 py-1 rounded text-xs transition-colors ${filterPriority === 'all' ? 'bg-gray-700 text-gray-200' : 'text-gray-500 hover:text-gray-300'}`}
            >All</button>
            {(['critical', 'high', 'medium', 'low'] as TaskPriority[]).map(p => (
              <button
                key={p}
                onClick={() => setFilterPriority(p)}
                className={`px-2 py-1 rounded text-xs transition-colors ${filterPriority === p ? 'bg-gray-700 text-gray-200' : 'text-gray-500 hover:text-gray-300'}`}
              >{PRIORITY_CONFIG[p].label}</button>
            ))}
          </div>
          <button onClick={() => setShowNewTask(true)} className="btn-primary flex items-center gap-1.5">
            <Plus className="w-4 h-4" />
            <span className="hidden sm:inline">New Task</span>
          </button>
        </div>
      </div>

      {viewMode === 'kanban' ? (
        <div className="flex-1 overflow-x-auto p-4 lg:p-6">
          <div className="flex gap-4 h-full min-w-max">
            {TASK_COLUMNS.map(col => {
              const colTasks = filteredTasks.filter(t => t.status === col.id);
              return (
                <div
                  key={col.id}
                  className="w-64 lg:w-72 flex flex-col bg-gray-900/30 rounded-xl border border-gray-800/30 transition-all"
                  onDragOver={handleDragOver}
                  onDrop={e => onDrop(e, col.id)}
                  onDragEnter={onDragEnter}
                  onDragLeave={onDragLeave}
                >
                  <div className="px-4 py-3 flex items-center justify-between border-b border-gray-800/30">
                    <h3 className="text-xs font-semibold text-gray-400 uppercase tracking-wider">{col.label}</h3>
                    <span className="text-[10px] bg-gray-800 text-gray-500 px-1.5 py-0.5 rounded-full font-medium">{colTasks.length}</span>
                  </div>
                  <div className="flex-1 p-2 space-y-2 overflow-y-auto">
                    {colTasks.map(task => {
                      const unresolvedBlockers = (task.dependencies || []).filter(depId => {
                        const dep = tasks.find(t => t.id === depId);
                        return dep && !['verified', 'done'].includes(dep.status);
                      });
                      return (
                        <TaskCard
                          key={task.id}
                          task={task}
                          agents={task.assigned_agent_id ? [agents.find(a => a.id === task.assigned_agent_id)!].filter(Boolean) : []}
                          isBlocked={unresolvedBlockers.length > 0}
                          blockerCount={unresolvedBlockers.length}
                          onClick={() => setSelectedTask(task)}
                        />
                      );
                    })}
                    {colTasks.length === 0 && (
                      <div className="py-8 text-center text-xs text-gray-700">
                        Drop tasks here
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      ) : (
        <div className="flex-1 p-4 lg:p-6">
          <GraphView tasks={filteredTasks} onTaskClick={setSelectedTask} />
        </div>
      )}

      {showNewTask && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm" onClick={() => setShowNewTask(false)}>
          <div className="card p-6 w-full max-w-md mx-4 animate-fade-in" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-semibold">New Task</h2>
              <button onClick={() => setShowNewTask(false)} className="btn-ghost p-1"><X className="w-4 h-4" /></button>
            </div>
            <div className="space-y-3">
              <input
                className="input"
                placeholder="Task title"
                value={newTitle}
                onChange={e => setNewTitle(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleRequestForecast()}
                autoFocus
              />
              <textarea
                className="textarea h-24"
                placeholder="Description (optional)"
                value={newDesc}
                onChange={e => setNewDesc(e.target.value)}
              />
              <div>
                <label className="text-xs text-gray-500 mb-1 block">Priority</label>
                <div className="flex gap-2">
                  {(['critical', 'high', 'medium', 'low'] as TaskPriority[]).map(p => (
                    <button
                      key={p}
                      onClick={() => setNewPriority(p)}
                      className={`flex-1 py-1.5 rounded-lg text-xs font-medium transition-colors ${
                        newPriority === p ? `${PRIORITY_CONFIG[p].bg} text-white` : 'bg-gray-800 text-gray-400 hover:bg-gray-700'
                      }`}
                    >{PRIORITY_CONFIG[p].label}</button>
                  ))}
                </div>
              </div>
              <button onClick={handleRequestForecast} className="btn-primary w-full flex items-center justify-center gap-2" disabled={!newTitle.trim() || checkingDuplicates}>
                {checkingDuplicates ? (
                  <>
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                    Checking for duplicates...
                  </>
                ) : (
                  'Review Forecast'
                )}
              </button>
            </div>
          </div>
        </div>
      )}

      {showForecast && (
        <TaskForecastPanel
          title={newTitle.trim()}
          description={newDesc.trim()}
          priority={newPriority}
          onProceed={handleProceedWithForecast}
          onNarrowScope={handleNarrowScope}
          onCancel={() => {
            setShowForecast(false);
            setShowNewTask(true);
          }}
        />
      )}

      {showCriteria && pendingForecast && (
        <AcceptanceCriteriaPanel
          title={newTitle.trim()}
          description={newDesc.trim()}
          forecast={pendingForecast}
          onProceed={handleProceedWithCriteria}
          onBack={() => {
            setShowCriteria(false);
            setShowForecast(true);
          }}
          onCancel={() => {
            setShowCriteria(false);
            setPendingForecast(null);
            setShowNewTask(true);
          }}
        />
      )}

      {showDepSuggestions && (
        <DependencySuggestionPanel
          title={newTitle.trim()}
          description={newDesc.trim()}
          existingTasks={tasks}
          onProceed={handleDepsProceed}
          onSkip={handleDepsSkip}
          onCancel={() => {
            setShowDepSuggestions(false);
            setShowNewTask(true);
          }}
        />
      )}

      {duplicates && duplicates.length > 0 && (
        <DuplicateDetectionPanel
          matches={duplicates}
          onLink={handleDuplicateLink}
          onContinue={handleDuplicateContinue}
          onCancel={() => {
            setDuplicates(null);
            setShowNewTask(true);
          }}
        />
      )}

      {selectedTask && (
        <TaskDetailPanel
          task={selectedTask}
          agents={agents}
          allTasks={tasks}
          onClose={() => setSelectedTask(null)}
          onUpdate={loadData}
          onDelete={async () => {
            await deleteTask(selectedTask.id);
            setSelectedTask(null);
            loadData();
          }}
        />
      )}
    </div>
  );
}

