export async function fetchTasks(): Promise<Task[]> {
  return readLocalTasks(false);
}

export async function createTask(task: Partial<Task>): Promise<Task> {
  return localCreateTask({ ...task, tags: task.tags || [] });
}

export async function updateTask(id: string, updates: Partial<Task>): Promise<Task> {
  return localUpdateTask(id, updates);
}

export async function deleteTask(id: string): Promise<void> {
  return localDeleteTask(id);
}

export async function setTaskAssignee(taskId: string, agentId: string | null, actorName = 'Team', note?: string): Promise<Task> {
  if (!agentId) {
    // Fetch the current task from local storage
    const tasks = await readLocalTasks(true);
    const task = tasks.find(t => t.id === taskId);
    if (!task) throw new Error(`Task ${taskId} not found`);

    const updates: Partial<Task> = { assigned_agent_id: null };
    if (task.assigned_agent_id) {
      await supabase.from('agents').update({ current_task_id: null, status: 'idle' }).eq('id', task.assigned_agent_id);
      if (task.status === 'in_progress') updates.status = 'ready';
    }
    const updated = await localUpdateTask(taskId, updates);
    await logActivity(taskId, 'Cleared task assignee', 'human', actorName, note);
    return updated;
  }

  // Assign agent: update task locally, update agent in Supabase
  const updated = await localUpdateTask(taskId, {
    assigned_agent_id: agentId,
    status: 'in_progress',
  });
  await supabase.from('agents').update({ current_task_id: taskId, status: 'busy' }).eq('id', agentId);
  await logActivity(taskId, 'Assigned agent to task', 'human', actorName, note);
  return updated;
}

