/**
 * local-tasks.ts
 *
 * Client-side module for reading/writing tasks and task-activity
 * from local JSON files stored in {projectPath}/.autolab/
 *
 * In dev mode, calls the Vite middleware at /api/local-tasks.
 * In production (preview), calls the standalone api-server at :4174.
 */

import { getCurrentProjectPath } from './project-store';
import type { Task, TaskActivity, TaskStatus, SenderType } from './types';

// ─── helpers ─────────────────────────────────────────────────────────────────

// In dev mode, Vite middleware handles /api/* on the same origin.
// In production/preview, the standalone api-server runs on port 4174.
const API_BASE = import.meta.env.DEV ? '' : `http://${window.location.hostname}:4174`;

function projectPath(): string {
  return getCurrentProjectPath();
}

async function request<T>(
  url: string,
  opts?: RequestInit,
): Promise<T> {
  const res = await fetch(url, opts);
  if (!res.ok) {
    const msg = await res.text().catch(() => res.statusText);
    throw new Error(`local-tasks API error ${res.status}: ${msg}`);
  }
  return res.json() as Promise<T>;
}

// ─── tasks ───────────────────────────────────────────────────────────────────

/** Read all tasks for the current project (excludes archived by default). */
export async function readLocalTasks(includeArchived = false): Promise<Task[]> {
  const path = projectPath();
  const url = `${API_BASE}/api/local-tasks?projectPath=${encodeURIComponent(path)}&includeArchived=${includeArchived}`;
  const tasks = await request<Task[]>(url);
  return tasks;
}

/** Create a new task — server assigns UUID + timestamps. */
export async function localCreateTask(partial: Partial<Task>): Promise<Task> {
  const path = projectPath();
  return request<Task>(`${API_BASE}/api/local-tasks`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ projectPath: path, task: partial }),
  });
}

/** Update fields on an existing task. */
export async function localUpdateTask(id: string, updates: Partial<Task>): Promise<Task> {
  const path = projectPath();
  return request<Task>(`${API_BASE}/api/local-tasks/${encodeURIComponent(id)}`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ projectPath: path, updates }),
  });
}

/** Delete a task by id. */
export async function localDeleteTask(id: string): Promise<void> {
  const path = projectPath();
  await request<void>(
    `${API_BASE}/api/local-tasks/${encodeURIComponent(id)}?projectPath=${encodeURIComponent(path)}`,
    { method: 'DELETE' },
  );
}

// ─── task activity ────────────────────────────────────────────────────────────

/** Read task activity entries. */
export async function readLocalActivity(
  taskId?: string,
  limit = 30,
): Promise<TaskActivity[]> {
  const path = projectPath();
  let url = `${API_BASE}/api/local-task-activity?projectPath=${encodeURIComponent(path)}&limit=${limit}`;
  if (taskId) url += `&taskId=${encodeURIComponent(taskId)}`;
  return request<TaskActivity[]>(url);
}

/** Append a task activity entry. */
export async function appendLocalActivity(
  taskId: string | null,
  action: string,
  actorType: SenderType = 'system',
  actorName = 'System',
  details?: string,
): Promise<void> {
  const path = projectPath();
  await request<void>(`${API_BASE}/api/local-task-activity`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      projectPath: path,
      entry: {
        task_id: taskId,
        actor_type: actorType,
        actor_name: actorName,
        action,
        details: details || null,
      },
    }),
  });
}

// ─── status helpers ───────────────────────────────────────────────────────────

/** Simple status transition (no RPC, no validation). */
export async function localMoveTask(id: string, newStatus: TaskStatus): Promise<void> {
  await localUpdateTask(id, { status: newStatus });
}

